# General utility module providing common helper functions and classes

# Static utility class with mathematical helpers
class MathUtils:
    @static
    PI: float = 3.14159

    @static
    def clamp(value: float, min_val: float, max_val: float) -> float:
        if value < min_val:
            return min_val
        if value > max_val:
            return max_val
        return value

    @static
    def square(x: float) -> float:
        return x * x

# String manipulation utilities
class StringUtils:
    @static
    def truncate(s: str, max_len: int) -> str:
        if len(s) <= max_len:
            return s
        return s[0:max_len] + "..."

# Standalone utility function
def format_number(n: float, decimals: int) -> str:
    factor: int = 1
    i: int = 0
    while i < decimals:
        factor = factor * 10
        i = i + 1
    rounded: int = int(n * factor)
    whole: int = rounded // factor
    frac: int = rounded % factor
    if decimals == 0:
        return str(whole)
    # Build fractional part with leading zeros
    frac_str: str = str(frac)
    while len(frac_str) < decimals:
        frac_str = "0" + frac_str
    return str(whole) + "." + frac_str

