# Geometry utilities that build on the general utils module
from utils import MathUtils, StringUtils, format_number

# Abstract base class for shapes
class Shape:
    name: str

    def __init__(self, name: str):
        self.name = name

    @virtual
    def get_area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return "Shape: " + self.name

# Circle implementation
class Circle(Shape):
    radius: float

    def __init__(self, radius: float):
        super().__init__("Circle")
        self.radius = radius

    @override
    def get_area(self) -> float:
        # Using the imported utility
        return MathUtils.PI * MathUtils.square(self.radius)

    @override
    def describe(self) -> str:
        area: float = self.get_area()
        # Use imported format_number function
        area_str: str = format_number(area, 2)
        return self.name + " with radius " + format_number(self.radius, 1) + ", area " + area_str

# Rectangle implementation
class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, width: float, height: float):
        super().__init__("Rectangle")
        self.width = width
        self.height = height

    @override
    def get_area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        w_str: str = format_number(self.width, 1)
        h_str: str = format_number(self.height, 1)
        a_str: str = format_number(self.get_area(), 1)
        desc: str = self.name + " " + w_str + "x" + h_str + " = " + a_str
        # Use StringUtils to truncate if too long
        return StringUtils.truncate(desc, 40)
